select count(*)
from reports
where member_id = #{memberId}
	and target_type = #{targetType}
	and target_id = #{targetId}
	and delete_yn = 'N'

select target_member_id from ( select r.report_id, mt.member_id as target_member_id from reports r join meetups mt on r.target_id = mt.meetup_id where r.target_type = 'MEETUP'
union all
select r.report_id, rv.member_id as target_member_id from reports r join reviews rv on r.target_id = rv.review_id where r.target_type = 'REVIEW' ) where report_id = #{reportId}

select target_nickname from ( select r.report_id, m.nickname as target_nickname from reports r join meetups mt on r.target_id = mt.meetup_id join members m on mt.member_id = m.member_id where r.target_type = 'MEETUP'
union all
select r.report_id, m.nickname as target_nickname from reports r join reviews rv on r.target_id = rv.review_id join members m on rv.member_id = m.member_id where r.target_type = 'REVIEW' ) where report_id = #{reportId}

select count(*) from ( select mt.member_id as target_member_id from reports r join meetups mt on r.target_id = mt.meetup_id where r.target_type = 'MEETUP' and r.status = 'APPROVED'
union all
select rv.member_id as target_member_id from reports r join reviews rv on r.target_id = rv.review_id where r.target_type = 'REVIEW' and r.status = 'APPROVED' ) where target_member_id = #{targetMemberId}

select count(*) from ( select r.report_id, mt.member_id as target_member_id from reports r join meetups mt on r.target_type = 'MEETUP' and r.target_id = mt.meetup_id and r.status = 'APPROVED' and r.delete_yn = 'N' and r.updated_at >= sysdate -90
union all
select r.report_id, rv.member_id as target_member_id from reports r join reviews rv on r.target_type = 'REVIEW' and r.target_id = rv.review_id and r.status = 'APPROVED' and r.delete_yn = 'N' and r.updated_at >= sysdate -90 ) where target_member_id = #{targetMemberId}

